5499	\begin{lemma}[Dual of the structure sheaf]
5500	  \label{lem:dual_unit_iso}
5501	  \lean{AlgebraicGeometry.Scheme.Modules.dual_unit_iso}
5502	  \uses{lem:internal_hom_eval, lem:internal_hom_isSheaf, lem:tensorobj_unit_iso}
5503	  Let \(Y\) be a scheme. The sheaf-level dual of the structure sheaf is canonically the
5504	  structure sheaf itself,
5505	  \[
5506	    \mathtt{dual}\,\mathcal{O}_Y \;\xrightarrow{\ \sim\ }\; \mathcal{O}_Y,
5507	  \]
5508	  obtained by sheafifying the presheaf-level ``evaluation at \(1\)'' isomorphism
5509	  \(\mathcal{H}om(\mathbf{1}, \mathbf{1}) \cong \mathbf{1}\): every endomorphism of the
5510	  unit presheaf is multiplication by its value at the global section \(1\), so evaluation
5511	  at \(1\) identifies the internal hom of the unit into itself with the unit.
5512	\end{lemma}
5513	
5514	\begin{proof}
5515	  \uses{lem:internal_hom_eval, lem:internal_hom_isSheaf, lem:tensorobj_unit_iso}
5516	  At the presheaf level the dual of the unit \(\mathbf{1} = \mathcal{O}_Y\) is the internal
5517	  hom \(\mathcal{H}om(\mathbf{1}, \mathbf{1})\), whose value on an open \(U\) is the module
5518	  of \(\mathcal{O}(U)\)-linear endomorphisms of \(\mathbf{1}|_U\). Each such endomorphism is
5519	  determined by its value at the global section \(1\) and equals multiplication by that
5520	  value; hence evaluation at \(1\) --- the internal-hom evaluation
5521	  \cref{lem:internal_hom_eval} of the unit, composed with the left unitor
5522	  \(\mathbf{1} \otimes \mathbf{1} \cong \mathbf{1}\) of \cref{lem:tensorobj_unit_iso} --- is
5523	  an isomorphism \(\mathcal{H}om(\mathbf{1}, \mathbf{1}) \cong \mathbf{1}\) of presheaves of
5524	  modules. Sheafifying through the sheaf-level dual of \cref{lem:internal_hom_isSheaf}
5525	  yields \(\mathtt{dual}\,\mathcal{O}_Y \cong \mathcal{O}_Y\).
5526	\end{proof}
